using System;
using Wrap.Logging;

namespace Wrap;

/// <summary>
/// Marks a partial method as a Failure to be generated by the FailureValue source generator.
/// </summary>
[AttributeUsage(AttributeTargets.Method, AllowMultiple = false)]
public sealed class FailureAttribute : Attribute
{
	/// <summary>
	/// Failure message (containing placeholders matching the names of the method parameters).
	/// </summary>
	public string Message { get; private init; }

	/// <summary>
	/// Failure log level - if not set will use <see cref="FailureValue.DefaultFailureLevel"/>.
	/// </summary>
	public LogLevel Level { get; private init; }

	/// <summary>
	/// Create Failure with message.
	/// </summary>
	/// <param name="message">Failure message.</param>
	public FailureAttribute(string message) :
		this(message, FailureValue.DefaultFailureLevel)
	{ }

	/// <summary>
	/// Create Failure with message and log level.
	/// </summary>
	/// <param name="message">Failure message.</param>
	/// <param name="level">Log level.</param>
	public FailureAttribute(string message, LogLevel level) =>
		(Message, Level) = (message, level);
}
